k = int(next(it))
def subarrays_with_k_distinct(arr, k):
    def at_most(k):
        left = 0
        count = {}
        distinct = 0
        res = 0
        for right in range(len(arr)):
            count[arr[right]] = count.get(arr[right], 0) + 1
            if count[arr[right]] == 1:
                distinct += 1
            while distinct > k:
                count[arr[left]] -= 1
                if count[arr[left]] == 0:
                    distinct -= 1
                left += 1
            res += right - left + 1
        return res
    return at_most(k) - at_most(k - 1)
print(subarrays_with_k_distinct(arr, k))

