#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];
    int k;
    cin >> k;
    auto at_most = [&](int k){
        int left = 0;
        unordered_map<int, int> count;
        int distinct = 0;
        long long res = 0;
        for(int right = 0; right < n; right++){
            count[arr[right]]++;
            if(count[arr[right]] == 1) distinct++;
            while(distinct > k){
                count[arr[left]]--;
                if(count[arr[left]] == 0) distinct--;
                left++;
            }
            res += right - left + 1;
        }
        return res;
    };
    cout << at_most(k) - at_most(k - 1) << endl;
    return 0;
}
